import React, { useState, useEffect, useContext } from 'react';
import api from '../utils/api';
import { AuthContext } from '../context/AuthContext';
import { Link } from 'react-router-dom';
import NearbyWorkersModal from '../components/NearbyWorkersModal';
import './Dashboard.css';

const EmployerDashboard = () => {
  const { user } = useContext(AuthContext);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [stats, setStats] = useState(null);
  const [recentJobs, setRecentJobs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedCategory, setSelectedCategory] = useState(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isEmergency, setIsEmergency] = useState(false);

  useEffect(() => {
    if (activeTab === 'dashboard') {
      fetchDashboardData();
    }
  }, [activeTab]);

  const fetchDashboardData = async () => {
    try {
      const response = await api.get('/employers/dashboard');
      setStats(response.data.stats);
      setRecentJobs(response.data.recentJobs);
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
    } finally {
      setLoading(false);
    }
  };

  const categories = [
    { id: 'painting', label: 'Painting', icon: '🎨' },
    { id: 'electrical', label: 'Electrical', icon: '⚡' },
    { id: 'masonry', label: 'Masonry', icon: '🧱' },
    { id: 'plumbing', label: 'Plumbing', icon: '🚰' },
    { id: 'carpentry', label: 'Carpentry', icon: '🪚' },
    { id: 'welding', label: 'Welding', icon: '🔥' },
    { id: 'construction', label: 'Construction', icon: '🏗️' },
    { id: 'cleaning', label: 'Cleaning', icon: '🧹' },
    { id: 'gardening', label: 'Gardening', icon: '🌱' },
    { id: 'loading', label: 'Loading', icon: '📦' },
    { id: 'fabrication', label: 'Fabrication', icon: '🛠️' },
    { id: 'tiling', label: 'Tiling', icon: '📐' }
  ];

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return (
          <>
            <div className="stats-grid">
              <div className="stat-card">
                <h3>Jobs Posted</h3>
                <p className="stat-value">{stats?.totalJobsPosted || 0}</p>
              </div>
              <div className="stat-card">
                <h3>Active Jobs</h3>
                <p className="stat-value">{stats?.activeJobs || 0}</p>
              </div>
              <div className="stat-card">
                <h3>Total Spent</h3>
                <p className="stat-value">₹{stats?.totalSpent || 0}</p>
              </div>
              <div className="stat-card">
                <h3>Pending Applications</h3>
                <p className="stat-value">{stats?.pendingApplications || 0}</p>
              </div>
            </div>

            <div className="service-quick-links">
              <h3>Quick Hire Services</h3>
              <div className="quick-links-grid">
                {categories.slice(0, 6).map(cat => (
                  <div key={cat.id} className="quick-link-card-wrapper">
                    <div className="quick-link-card" onClick={() => setSelectedCategory(cat.id)}>
                      <span className="q-icon">{cat.icon}</span>
                      <span>{cat.label}</span>
                    </div>
                    {selectedCategory === cat.id && (
                      <div className="category-actions">
                        <button 
                          className="btn-nearby"
                          onClick={() => {
                            setIsEmergency(false);
                            setIsModalOpen(true);
                          }}
                        >
                          👥 Nearby Workers
                        </button>
                        <button 
                          className="btn-emergency"
                          onClick={() => {
                            setIsEmergency(true);
                            setIsModalOpen(true);
                          }}
                        >
                          🚨 Emergency Work
                        </button>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>

            <section className="dashboard-content">
              <div className="content-header">
                <h2>Recent Postings</h2>
                <Link to="/post-job" className="post-job-btn">Post New Job</Link>
              </div>
              <div className="jobs-list">
                {recentJobs.length > 0 ? (
                  recentJobs.map(job => (
                    <div key={job._id} className="job-card">
                      <div className="job-info">
                        <h3>{job.title}</h3>
                        <p className={`status-badge ${job.status}`}>{job.status}</p>
                        <p className="job-meta">Posted on {new Date(job.createdAt).toLocaleDateString()}</p>
                      </div>
                      <div className="job-action">
                        <p className="app-count">{job.applications?.length || 0} Applications</p>
                        <Link to={`/job/${job._id}`} className="view-btn">Manage</Link>
                      </div>
                    </div>
                  ))
                ) : (
                  <p className="no-data">No active job postings found.</p>
                )}
              </div>
            </section>
          </>
        );
      case 'history':
        return (
          <div className="tab-content-area">
            <h2>Work History</h2>
            <p className="coming-soon">Your past hiring records and completed projects will appear here.</p>
          </div>
        );
      case 'settings':
        return (
          <div className="tab-content-area">
            <h2>Account Settings</h2>
            <div className="settings-options">
              <div className="setting-item">
                <label>Profile Visibility</label>
                <input type="checkbox" defaultChecked />
              </div>
              <div className="setting-item">
                <label>Email Notifications</label>
                <input type="checkbox" defaultChecked />
              </div>
            </div>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="dashboard-layout">
      <aside className="dashboard-sidebar">
        <div className="sidebar-header">
          <div className="employer-avatar">
            {user?.name?.charAt(0) || 'E'}
          </div>
          <h3>{user?.name}</h3>
          <p>Employer</p>
        </div>
        <nav className="sidebar-nav">
          <button 
            className={`nav-item ${activeTab === 'dashboard' ? 'active' : ''}`}
            onClick={() => setActiveTab('dashboard')}
          >
            <span className="nav-icon">📊</span> Dashboard
          </button>
          <button 
            className={`nav-item ${activeTab === 'history' ? 'active' : ''}`}
            onClick={() => setActiveTab('history')}
          >
            <span className="nav-icon">📜</span> History
          </button>
          <button 
            className={`nav-item ${activeTab === 'settings' ? 'active' : ''}`}
            onClick={() => setActiveTab('settings')}
          >
            <span className="nav-icon">⚙️</span> Settings
          </button>
        </nav>
      </aside>

      <main className="dashboard-main">
        {loading && activeTab === 'dashboard' ? (
          <div className="loading">Loading...</div>
        ) : (
          renderContent()
        )}
      </main>

      <NearbyWorkersModal
        isOpen={isModalOpen}
        onClose={() => {
          setIsModalOpen(false);
          setSelectedCategory(null);
        }}
        category={selectedCategory}
        isEmergency={isEmergency}
      />
    </div>
  );
};

export default EmployerDashboard;
